// src/pages/Donate.js
import React from 'react';
import { Elements } from '@stripe/react-stripe-js';
import { loadStripe } from '@stripe/stripe-js';
import PaymentForm from '../components/PaymentForm';
import './Payment.css';

const stripePromise = loadStripe('pk_test_51RFfpPI7FWu561A0WglXKU8G05G51nieOuNPj4YR2CXvoLocst2D7jFcrP4hcqC670uo4ZNB7y1DB6WvaQ1HrP1400LCZS6PZD');

const Payment = () => {
  const options = {
    mode: 'payment',
    amount: 1000,
    currency: 'usd',
    appearance: {
      theme: 'stripe',
    },
  };

  return (
    <div className="payment-container">
      <div className="payment-header">
        <h1>Make a Donation</h1>
        <p>Support our wildlife conservation efforts</p>
      </div>

      <div className="payment-content">
        <Elements stripe={stripePromise} options={options}>
          <PaymentForm />
        </Elements>
      </div>
    </div>
  );
};

export default Payment;
